#include <memory>

// Define Parent and Child. Parent owns Child (shared_ptr); Child points back at
// Parent. Choose the pointer type for the back-pointer so the objects are
// destroyed (no leak). Each destructor prints "<Type> <id> destroyed".

int main()
{
    int pid{};
    int cid{};
    std::cin >> pid >> cid;

    // Create parent and child, link both directions, keep an independent
    // weak_ptr<Parent> "watch", then report counts, observe through the child's
    // back-pointer, and release the pointers.

    return 0;
}

solution_code:
#include <iostream>
#include <memory>

struct Child;

struct Parent
{
    int id;
    std::shared_ptr<Child> child;
    Parent(int id) : id{ id } {}
    ~Parent() { std::cout << "Parent " << id << " destroyed\n"; }
};

struct Child
{
    int id;
    std::weak_ptr<Parent> parent;
    Child(int id) : id{ id } {}
    ~Child() { std::cout << "Child " << id << " destroyed\n"; }
};

int main()
{
    int pid{};
    int cid{};
    std::cin >> pid >> cid;

    auto parent{ std::make_shared<Parent>(pid) };
    auto child{ std::make_shared<Child>(cid) };
    parent->child = child;
    child->parent = parent;

    std::weak_ptr<Parent> watch{ parent };

    std::cout << "owners of parent: " << parent.use_count() << '\n';
    if (auto p{ child->parent.lock() })
        std::cout << "child sees parent: " << p->id << '\n';

    std::cout << std::boolalpha;
    child.reset();
    std::cout << "watch expired before: " << watch.expired() << '\n';
    parent.reset();
    std::cout << "watch expired after: " << watch.expired() << '\n';

    return 0;
}

