    // Process q copy/drop/peek/count commands, accessing the object only
    // through the observer's lock().

    return 0;
}

solution_code:
#include <iostream>
#include <memory>
#include <string>
#include <vector>

int main()
{
    int value{};
    int q{};
    std::cin >> value >> q;

    std::vector<std::shared_ptr<int>> owners;
    owners.push_back(std::make_shared<int>(value));
    std::weak_ptr<int> observer{ owners.front() };

    for (int i{ 0 }; i < q; ++i)
    {
        std::string cmd{};
        std::cin >> cmd;

        if (cmd == "copy")
        {
            if (!owners.empty())
                owners.push_back(owners.back());
        }
        else if (cmd == "drop")
        {
            if (!owners.empty())
                owners.pop_back();
        }
        else if (cmd == "peek")
        {
            if (auto sp{ observer.lock() })
                std::cout << "value: " << *sp << '\n';
            else
                std::cout << "value: expired\n";
        }
        else if (cmd == "count")
        {
            std::cout << "owners: " << observer.use_count() << '\n';
        }
    }

    return 0;
}
